const output = [];

for (const item of $input.all()) {

  if (!item.binary) continue;

  for (const key of Object.keys(item.binary)) {

    const file = item.binary[key];

    const ext = (file.fileExtension || "").toLowerCase();

    if (["pdf", "docx", "txt"].includes(ext)) {

      output.push({
        json: {
          filename: file.fileName,
          extension: ext,
          mimeType: file.mimeType,
          sender: item.json.from,
          subject: item.json.subject,
          date: item.json.date
        },
        binary: {
          data: file
        }
      });

    }

  }

}

return output;

const text = $json.text ?? "";

if (!text.trim()) {
  throw new Error("Resume text is empty.");
}

const cleaned = text
  .normalize("NFKC")
  .replace(/\u00A0/g, " ")
  .replace(/[\u200B-\u200D\uFEFF]/g, "")
  .replace(/\r\n/g, "\n")
  .replace(/\r/g, "\n")
  .replace(/\t/g, " ")
  .replace(/[ ]{2,}/g, " ")
  .replace(/\n{3,}/g, "\n\n")
  .replace(/[^\S\n]+$/gm, "")
  .trim();

return [{
  json: {
    text: cleaned,
    stats: {
      characters: cleaned.length,
      words: cleaned.split(/\s+/).filter(Boolean).length,
      lines: cleaned.split("\n").length
    }
  }
}];

// Get cleaned resume text
const text = ($json.text || "").trim();

if (!text) {
  throw new Error("Resume text is empty after cleaning.");
}

// Standardize resume text
let standardized = text

  // Normalize Unicode
  .normalize("NFKC")

  // Normalize line endings
  .replace(/\r\n/g, "\n")
  .replace(/\r/g, "\n")

  // Remove invisible characters
  .replace(/[\u200B-\u200D\uFEFF]/g, "")

  // Replace non-breaking spaces
  .replace(/\u00A0/g, " ")

  // Standardize bullets
  .replace(/[•●▪◦■□►▶➤✓✔]/g, "- ")

  // Standardize dashes
  .replace(/[–—]/g, "-")

  // Remove multiple spaces
  .replace(/[ \t]{2,}/g, " ")

  // Remove trailing spaces
  .replace(/[ \t]+$/gm, "")

  // Keep maximum one blank line
  .replace(/\n{3,}/g, "\n\n")

  .trim();


// Common Resume Sections
const sections = [
  "Summary",
  "Profile",
  "Objective",
  "Education",
  "Experience",
  "Work Experience",
  "Professional Experience",
  "Internship",
  "Internships",
  "Projects",
  "Skills",
  "Technical Skills",
  "Soft Skills",
  "Certifications",
  "Achievements",
  "Awards",
  "Leadership",
  "Languages",
  "Relevant Coursework",
  "Publications",
  "Interests"
];

// Standardize section headings
sections.forEach(section => {
  const regex = new RegExp(`^\\s*${section}\\s*$`, "gim");
  standardized = standardized.replace(regex, `\n## ${section}\n`);
});

// Final cleanup
standardized = standardized
  .replace(/\n{3,}/g, "\n\n")
  .trim();

return [{
  json: {
    standardizedText: standardized,

    metadata: {
      characters: standardized.length,
      words: standardized.split(/\s+/).filter(Boolean).length,
      lines: standardized.split("\n").length,
      standardized: true,
      processedAt: new Date().toISOString()
    }
  }
}];

